#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=500005;
int n,fa[N];
stack<int> st;
ll sum[N],lst[N],ans;
string s;
vector<int> g[N];
void dfs(int u)
{
	int tmp=0;
	if(s[u]==')')
	{
		if(st.size())
		{
			tmp=st.top();
			lst[u]=lst[fa[tmp]]+1;
			st.pop();
		}
	}
	else if(s[u]=='(') st.push(u);
	sum[u]=sum[fa[u]]+lst[u];
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		dfs(v);
	}
	if(tmp!=0) st.push(tmp);
	else if(st.size()) st.pop(); 
}
int main()
{
//	freopen("ex_brackets3.in","r",stdin);
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>s;
	s=" "+s;
	for(int i=2;i<=n;i++)
	{
		cin>>fa[i];
		g[fa[i]].push_back(i);
	}
	dfs(1);
	for(int i=1;i<=n;i++)
	{
		ans=ans^(sum[i]*i);
	}
	cout<<ans;
	return 0;
}
